uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  //==============>>>>>>>>> Setting Up All The Lighting Data <<<<<<<<<====================
//---------------------------------------------------------------------------------------
// Sample the current texel, take its' blue value to be its 3D z value & build its' vector
    vec3 TexColor = texture(sampler_main, vUv).xyz;
    float TexHeight = TexColor.z;
    vec3 vecToTex = vec3(vUv.x * uTexSize.x, vUv.y * uTexSize.y, TexHeight);//derived from vUv & blue channel of texel
    vec3 input = TexColor;
// Use the r & g channels & the Color Look Up Table to get a new vec3 color for the Texel.
//***********TODO3:  Pull material data from LUT before TexColor gets changed!!!
// Pull the material properties from the material samples (hardcoding is temp only!!!!!)
    float hardness = 0.05; //how pollished is the surface
    float metalic = 0.0; //how mirror like is the reflection
    float opacity = 1.0; //how transparent is this material
    float refIndex = 0.0; //how much does this material bend light
    vec3 transColor = vec3(1.0, 1.0, 1.0); //color of light that the material lets pass through itself
    vec2 fresnel = vec2(0.0, 0.0); //
    float subSurf = 0.25;
    vec3 subSurfColor = vec3(1.0, 1.0, 1.0);
    TexColor = texture(sampler_fw_ColorLUT, vec2(TexColor.x, TexColor.y)).xyz;//use ColorLUT
    TexColor = (TexHeight>0.00) * TexColor;// 0 out any pixel that falls into negative z space
// Sample the texel one step to the right, get its' height.
    vec2 Huv = vec2(vUv.x + uTexSize.z, vUv.y);
    vec3 Color = texture(sampler_main, Huv).xyz;
    vec3 HorHeight = Color.z;
// Sample the texel one step below, get its' height.
    vec2 Vuv = vec2(vUv.x, vUv.y + uTexSize.w);
    Color = texture(sampler_main, Vuv).xyz;
    float VrtHeight = Color.z;
// Use the sampled heights to calculate the surface normal for this texel
    float Hor = (TexHeight - HorHeight);// lateral angle
    float Vrt = (TexHeight - VrtHeight);// vertical angle
    vec3 TexNorm = vec3(Hor, Vrt, 0);
    // If Normal vector length > 1.0, normalize it to 1.0, else leave it as is:
    float normLength = sqrt(pow(TexNorm.x,2)+pow(TexNorm.y,2));
    TexNorm =  ((normLength > 1.0) * (TexNorm * (1.0 / normLength))) + ((normLength <= 1.0) * TexNorm);
    float z = sqrt(1 - (pow(TexNorm.x, 2) + pow(TexNorm.y, 2)));// Asking Pythagoras what z is
    TexNorm = vec3(TexNorm.x, TexNorm.y, z);// Putting it all together for a proper vector. (-1 to 1 ranged)
    TexNorm = normalize(TexNorm);
    vec3 DspNorm = (TexNorm + 1.0)*0.5;//  normal map, ranged for monitor display




// Camera -- Get the vector to the camera relative to the current pixel in pixels,
//  so as to give the aproximate location of the viewers head.
    vec3 vecToCam = vec3(0.5 * q10, 0.50 * q11, 1.15 * q10);//Where's your head at in screen coordinate space?
    vecToCam = vecToCam - vecToTex;//vector fom texel to your head in pixels
    vecToCam = normalize(vecToCam);

// Point Light--Get the Point Light vector and color data, then use data to get point light color.
    vec3 vecToPtL = vec3(q1,q2,q3);//provided in per uFrame
    vecToPtL = vecToPtL - vecToTex;//make vector relative to this texel
    float vTPLLength = sqrt(pow(vecToPtL.x,2)+pow(vecToPtL.y,2)+pow(vecToPtL.z,2));
    vecToPtL = normalize(vecToPtL);//normalize
    vec3 PtLColor = texture(sampler_fw_ColorLUT, vec2(q4, 0.5)).xyz;//use ColorLUT

// Environment Light--Using q6 = phi & q7 = theta to get the vector to the Environmental Light
    z = sin(q7);  float n = cos(q7);  float y = sin(q6) * n;  float x = cos(q6) * n;
    vec3 vecToEnL = vec3(x,y,z);//calculate from phi & theta
    vec3 EnLColor = texture(sampler_fw_ColorLUT, vec2(q8, q9)).xyz;//use ColorLUT


//=======================>>>>>>>>>>> Generate Lighting <<<<<<<<<<<<======================
//---------------------------------------------------------------------------------------
//***********TODO2: lay in material properties equations on both lights
// Generate the Environmental light contribution
    float EnLAngularFactor = (TexHeight > 0.0) * min(max(dot(TexNorm,vecToEnL),0.002),1.0);
    vec3 EnLContrib = pow(1.7 * EnLAngularFactor, 2) * EnLColor * TexColor;
// Generate Environmental light specular highlights
    vec3 EnLSpecVec = vec3(250 * vecToEnL.x + vecToCam.x, 250 * vecToEnL.y + vecToCam.y, 250 * vecToEnL.z + vecToCam.z);
    EnLSpecVec = normalize(EnLSpecVec);
    float EnLSAngFact = max(0.0, dot(EnLSpecVec, TexNorm));
    EnLSAngFact = pow((1 - sqrt(1 - pow(EnLSAngFact, 2))) * (TexHeight > 0.0), 1.0 + (hardness * 255));
    EnLContrib = mix(EnLContrib, EnLColor, EnLSAngFact);

// Generate point light contribution
    float PtLAngularFactor = (TexHeight > 0.0) * min(max(dot(TexNorm, vecToPtL),0.00),1.0);
    float brightness = q5;//***********TODO4: rework point light falloff
    float factor = (1.0 - brightness) * 0.01805;
    float falloff = 0.01805 + max(0,(1.0 - (vTPLLength * (0.000075 + factor))));//brightness of 1 = 0.00025 0 = 0.0183 gives a ranging factor of 0.01805
    vec3 PtLContrib = (PtLAngularFactor * falloff) * PtLColor * TexColor;
// Generate point lights specular highlight
    vec3 PtLSpecVec = vec3(vecToPtL.x + vecToCam.x, vecToPtL.y + vecToCam.y, vecToPtL.z + vecToCam.z);
    PtLSpecVec = normalize(PtLSpecVec);
    float PtLSAngFact = max(0.0, dot(PtLSpecVec, TexNorm));
    PtLSAngFact = pow((1 - sqrt(1 - pow(PtLSAngFact, 2))) * (TexHeight > 0.0), 1.0 + (hardness * 255));
    PtLContrib = mix(PtLContrib, min(PtLColor * q5, 1.0), PtLSAngFact);

ret = PtLContrib + EnLContrib;//PtLAngularFactor * falloff;//input;//EnLContrib;//DspNorm;//EnLAngularFactor;// distToPtL;// vec3(vUv.x, vUv.y, TexHeight);//
//ret = PtLSAngFact; //(1 + PtLSpecVec) * 0.5;

